import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Paper, FormControl} from '@material-ui/core';
import { ProfilePicture, TextFieldEditable, headerActions, headerStrings } from '../../includes';
import { trackerUtil, trackerUtilStrings } from '../utils';
import { profileActions } from './actions';


const style = theme => ({
    root: {
        padding : 20,
        display : "flex",
        height : "100%",
        justifyContent :"center",
    },
    paper : {
        position : "relative",
        height : "90%",
        width : "50%",
        [theme.breakpoints.down("sm")] :{
            width : "70%"
        },
        [theme.breakpoints.down("xs")] :{
            width : "100%"
        },
        
    },
    content : {
        height : "100%",
        width : "100%",
        overflow : "scroll"
    },
    profilePic : {
        padding : 20,
        backgroundColor : trackerUtil.getTheme().secondary,
    },
    settingArea : {
        padding : 20,
    },
    formControl : {
        padding : 20,
        width : "100%"
    },
})
class _MyProfile extends Component {
    constructor(props) {
        super(props);
        const {dispatch } = props;
        headerActions({
            [headerStrings.headerTitle] : "MY PROFILE",
            [headerStrings.headerRight] : null
        })(dispatch);
    }
    
    textOnChange = name => (value, context) => {
        const {dispatch} = this.props;
        const data = {[name] : value};
        profileActions.updateProfile(data, done => {
            context.setState({loading : false});
        })(dispatch);
    }
    uploadProfileImage = image => {
        profileActions.sendImage(image)(this.props.dispatch);
    }
    render() {
        const {
            classes,
            [trackerUtilStrings.myProfile] : profile
        } = this.props;
        return (
            <div className={classes.root}>
                <Paper className={classes.paper}>
                    <div className={classes.content}>
                            <ProfilePicture
                                editable
                                editIconHandler={()=>{}}
                                classes={{imgContainer : classes.profilePic}}
                                src="/images/laughing_boy.jpg"
                                title="tracking_profile_picture"
                                uploadImage={this.uploadProfileImage.bind(this)}/>
                            <div className={classes.settingArea}>
                                <FormControl className={classes.formControl}>
                                    <TextFieldEditable
                                        value={profile ? profile.name : ""}
                                        textFieldProps = {{
                                            label:"Name",
                                            placeholder:"Name",
                                            margin:"normal",
                                            inputProps : {
                                                id : "name"
                                            }
                                        }}
                                        doneCallback={this.textOnChange("name")}
                                        />     
                                </FormControl>
                                <FormControl className={classes.formControl}>
                                    <TextFieldEditable
                                        value={profile ? profile.email : ""}
                                        textFieldProps = {{
                                            label:"Email",
                                            placeholder:"Email",
                                            margin:"normal",
                                            inputProps : {
                                                id : "email"
                                            }
                                        }}
                                        doneCallback={this.textOnChange("email")}
                                        />     
                                </FormControl>
                                <FormControl className={classes.formControl}>                             
                                    <TextFieldEditable
                                        value={profile ? profile.phone : ""}
                                        phone
                                        textFieldProps = {{
                                            label:"Number",
                                            placeholder:"Number",
                                            margin:"normal",
                                            inputProps : {
                                                id : "number"
                                            }
                                        }}
                                        doneCallback={this.textOnChange("phone")}
                                        />                                   
                                </FormControl>
                            </div>
                    </div>
                </Paper>
            </div>
        );
    }
}


_MyProfile.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({trackerUtilReducer}) => ({
    [trackerUtilStrings.myProfile] : trackerUtilReducer[trackerUtilStrings.myProfile],
})


export const MyProfile = connect(mapStateToProps)(withStyles(style)(_MyProfile));
export {MyProfile as default}